from bs4 import BeautifulSoup

from bs4 import BeautifulSoup, Comment

def strip_html_code(html_content):
    """
    Strips <script>, <style>, <base>, <link>, <meta>, <svg> tags and their content,
    removes all comments, and removes all HTML attributes except for 'class' and 'id'.
    Retains the rest of the HTML tags and their text content.

    Args:
        html_content (str): The HTML code as a string.

    Returns:
        str: Cleaned HTML content with only allowed attributes.
    """

    # Parse the HTML content
    soup = BeautifulSoup(html_content, 'html.parser')

    # Remove <script>, <style>, <base>, <link>, <meta>, <svg> tags and their content
    for tag in soup(['script', 'style', 'base', 'meta', 'svg']):
        tag.decompose()

    # Remove all comments
    for comment in soup.find_all(text=lambda text: isinstance(text, Comment)):
        comment.extract()

    # Remove all attributes except 'class' and 'id'
    for tag in soup.find_all(True):  # True matches all tags
        allowed_attributes = {
            key: value
            for key, value in tag.attrs.items()
            if key in ['class', 'id']
        }
        tag.attrs = allowed_attributes

    # Return the modified HTML as a string
    return str(soup)

